        {
          "@type": "Question",
          "name": "When must a listed company file its quarterly financial results?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Quarterly results must be submitted to the stock exchange within 45 days of the end of each quarter, and annual audited results within 60 days of the financial year end, under Regulation 33 of the SEBI LODR Regulations 2015. For the quarter ended 30 June, the deadline is 14 August; for the year ended 31 March, it is 30 May."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between SEBI reporting timelines and Companies Act filing timelines?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "SEBI LODR timelines run from the quarter or year end and are measured in days from that date, while Companies Act timelines run from the annual general meeting, with AOC-4 due within 30 days and MGT-7 within 60 days of the AGM. A listed company must meet both sets, so the SEBI 60 day results filing comes months before the MCA filing."
          }
        },
        {
          "@type": "Question",
          "name": "What happens if a listed company misses a SEBI reporting deadline?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Stock exchanges levy a fine of Rs 5,000 per day of delay for non submission of financial results under the SEBI standard operating procedure circular, and continued default can lead to suspension of trading in the shares. The exchange also publishes the name of the defaulting entity, so the penalty is reputational as well as monetary."
          }
        }
